With.Cte:

				SELECT {{
							Fields
								-Dimension: Warehouses 
									--Table: WarehousesCte
								-Dimension: Products 
									--Table: ProductsCte
								-WithComma
                	   }}			   
					   {{
							IfRequest
								-Expression: NegativeStock
									--SUM(DataBaseWarehouses.NegativeStock) AS NegativeStock
								-Expression: NegativePendingReceptions
									--SUM(DataBaseWarehouses.NegativePendingReceptions) AS NegativePendingReceptions
						}}						   
					FROM Fact.DataBaseWarehouses
					{{
                		InnerJoin 
                			-Dimension: Warehouses 
                				--Table: WarehousesCte
							-Table: DataBaseWarehouses
							-On: WarehouseId-WarehouseId
					}}
	            	{{
	            		InnerJoin 
	            			-Dimension: Products 
	            				--Table: ProductsCte
							-Table: DataBaseWarehouses
							-On: ProductId-ProductId
	            	}}
					{{
                		GroupBy
                			-Dimension: Warehouses 
                				--Table: WarehousesCte
	            			-Dimension: Products 
	            				--Table: ProductsCte
	            	}}

With.Query:

				SELECT 
						{{
							Fields
								-Dimension: Warehouses
								-Dimension: Products
								-WithComma
                		}}
						{{
							IfRequest
								-Expression: NegativeStock
									--NegativeStock
								-Expression: NegativePendingReceptions
									--NegativePendingReceptions
								-WhenRequestTotals
									--Default
										---COUNT(*) OVER () AS TotalCount
									--Expression: NegativeStock
										---SUM(NegativeStock) OVER() AS TotalNegativeStock
									--Expression: NegativePendingReceptions
										---SUM(NegativePendingReceptions) OVER() AS TotalNegativePendingReceptions
							}}
					FROM GroupedCte
					{{
                		OrderBy
                			-Dimension: Warehouses
	            			-Dimension: Products
	            	}}
					{{Pagination}}
